INSERT INTO public.subtasks (id, created_at, task_id, title, status, assignee, position, completed_at) VALUES (13, '2026-02-01 14:04:29.45179+00', 27, '26/01 a 27/01: Foco: Deploy oficial e correção de erros críticos pós-lançamento. - Publicação oficial do sistema em produção via Vercel.  Correção do erro de "Type Error: statusConfig undefined" que causava o travamento da aba Pipeline. -  Implementação de sistema de Logs de Auditoria para rastrear edições e exclusões de itens.', 'done', 'Enzo', 5, '2026-01-27') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.subtasks (id, created_at, task_id, title, status, assignee, position, completed_at) VALUES (14, '2026-02-01 14:05:23.913394+00', 27, '29/01 - Foco: Resolução de problemas de conectividade e persistência de dados.  29 Jan: Correção do erro de conexão do Supabase (ERR_CONNECTION_REFUSED) através de novo script de inicialização do cliente. 29 Jan: Correção do Loop de Login Infinito e melhoria na persistência da sessão do usuário. 29 Jan: Otimização do Cache do Site para garantir que novas atualizações cheguem imediatamente aos usuários (Busting Service Worker).', 'done', 'Enzo', 6, '2026-01-29') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.subtasks (id, created_at, task_id, title, status, assignee, position, completed_at) VALUES (15, '2026-02-01 14:05:45.75898+00', 27, '30/01 - Foco: Flexibilidade do formulário e ferramentas para a diretoria.  30 Jan: Flexibilidade de Campos: Torna a "Data de Aniversário" opcional e adiciona o seletor de "Tipo de Contrato" (PME 1, PME 2, Corporativo). 30 Jan: Sincronização de Banco de Dados: Adição da coluna reanalise_obs e outras 12 colunas faltantes no Supabase para suportar novas métricas. 30 Jan: Expansão do Catálogo: Inclusão de 13 novos planos no seletor de "Plano Atual" (Assim, Porto, Unimed, Prevent Senior, etc.). 30 Jan: Fim do Limite de Caracteres: Aumento da altura dos campos de observação e remoção de travas de redimensionamento para textos longos.', 'done', 'Enzo', 7, '2026-01-30') ON CONFLICT (id) DO NOTHING;
